// SearchResults.js (inline styles version)
import React, { useState, useEffect } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { FaSearch, FaBook, FaFileAlt, FaHistory, FaArrowLeft } from 'react-icons/fa';

const SearchResults = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const query = new URLSearchParams(location.search).get('q') || '';
  
  const [results, setResults] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeFilter, setActiveFilter] = useState('all');

  useEffect(() => {
    if (query) {
      fetchSearchResults(query);
    }
  }, [query]);

  const fetchSearchResults = (searchQuery) => {
    setLoading(true);
    
    // Mock data
    const mockResults = [
      { id: 1, type: 'course', title: 'BCA', description: 'Bachelor of Computer Applications', icon: '📱', path: '/course/2' },
      { id: 2, type: 'subject', title: 'Programming in C', description: 'BCA Semester 1 Subject', icon: '💻', path: '/course/2/year/1/sem/1' },
      { id: 3, type: 'notes', title: 'C Programming Notes', description: 'Complete notes with examples', icon: '📝', path: '/materials/101' },
      { id: 4, type: 'pyq', title: 'BCA PYQs 2023', description: 'Previous year question papers', icon: '📄', path: '/pyqs/2023' },
      { id: 5, type: 'course', title: 'B.Tech', description: 'Bachelor of Technology', icon: '💻', path: '/course/1' },
      { id: 6, type: 'subject', title: 'Data Structures', description: 'B.Tech Semester 3 Subject', icon: '📚', path: '/course/1/year/2/sem/3' },
    ];

    const filteredResults = mockResults.filter(item =>
      item.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
      item.description.toLowerCase().includes(searchQuery.toLowerCase())
    );

    setTimeout(() => {
      setResults(filteredResults);
      setLoading(false);
    }, 500);
  };

  const filteredResults = activeFilter === 'all' 
    ? results 
    : results.filter(item => item.type === activeFilter);

  // Styles
  const styles = {
    container: {
      padding: '2rem',
      maxWidth: '1200px',
      margin: '0 auto',
      paddingTop: '90px',
      fontFamily: "'Inter', sans-serif"
    },
    header: {
      display: 'flex',
      alignItems: 'flex-start',
      gap: '2rem',
      marginBottom: '2rem',
    },
    backBtn: {
      display: 'flex',
      alignItems: 'center',
      gap: '0.5rem',
      padding: '0.75rem 1.5rem',
      background: '#f3f4f6',
      border: 'none',
      borderRadius: '8px',
      color: '#4b5563',
      fontWeight: '500',
      cursor: 'pointer',
      transition: 'all 0.3s',
      '&:hover': {
        background: '#e5e7eb',
        transform: 'translateX(-5px)'
      }
    },
    searchQuery: {
      flex: 1
    },
    title: {
      fontSize: '2rem',
      color: '#1f2937',
      marginBottom: '0.5rem',
      display: 'flex',
      alignItems: 'center',
      gap: '0.75rem'
    },
    queryText: {
      fontSize: '1.2rem',
      color: '#4f46e5',
      fontWeight: '600',
      marginBottom: '0.5rem'
    },
    resultCount: {
      color: '#6b7280',
      fontSize: '0.9rem'
    },
    filters: {
      display: 'flex',
      gap: '1rem',
      marginBottom: '2rem',
      flexWrap: 'wrap'
    },
    filterBtn: {
      display: 'flex',
      alignItems: 'center',
      gap: '0.5rem',
      padding: '0.75rem 1.5rem',
      background: '#f3f4f6',
      border: '2px solid transparent',
      borderRadius: '8px',
      color: '#4b5563',
      fontWeight: '500',
      cursor: 'pointer',
      transition: 'all 0.3s'
    },
    activeFilter: {
      background: '#4f46e5',
      color: 'white',
      borderColor: '#4f46e5'
    },
    resultsGrid: {
      display: 'grid',
      gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))',
      gap: '1.5rem'
    },
    resultCard: {
      background: 'white',
      borderRadius: '12px',
      padding: '1.5rem',
      boxShadow: '0 4px 6px rgba(0, 0, 0, 0.1)',
      border: '1px solid #e5e7eb',
      cursor: 'pointer',
      transition: 'all 0.3s',
      display: 'flex',
      gap: '1rem',
      '&:hover': {
        transform: 'translateY(-5px)',
        boxShadow: '0 10px 25px rgba(0, 0, 0, 0.15)',
        borderColor: '#4f46e5'
      }
    },
    resultIcon: {
      fontSize: '2rem',
      background: '#f3f4f6',
      width: '60px',
      height: '60px',
      borderRadius: '12px',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      flexShrink: 0
    },
    resultContent: {
      flex: 1
    },
    resultTitle: {
      fontSize: '1.1rem',
      color: '#1f2937',
      marginBottom: '0.5rem'
    },
    resultDesc: {
      color: '#6b7280',
      fontSize: '0.9rem',
      marginBottom: '0.75rem',
      lineHeight: '1.4'
    },
    resultType: {
      display: 'inline-block',
      padding: '0.25rem 0.75rem',
      borderRadius: '20px',
      fontSize: '0.75rem',
      fontWeight: '600'
    },
    loading: {
      textAlign: 'center',
      padding: '4rem'
    },
    spinner: {
      width: '50px',
      height: '50px',
      border: '4px solid #f3f4f6',
      borderTop: '4px solid #4f46e5',
      borderRadius: '50%',
      animation: 'spin 1s linear infinite',
      margin: '0 auto 1rem'
    },
    noResults: {
      textAlign: 'center',
      padding: '4rem'
    },
    searchAgainBtn: {
      padding: '0.75rem 2rem',
      background: 'linear-gradient(90deg, #4f46e5, #7c3aed)',
      color: 'white',
      border: 'none',
      borderRadius: '8px',
      fontWeight: '600',
      cursor: 'pointer',
      transition: 'all 0.3s',
      marginTop: '1rem'
    }
  };

  return (
    <div style={styles.container}>
      {/* Header */}
      <div style={styles.header}>
        <button 
          style={styles.backBtn}
          onClick={() => navigate(-1)}
        >
          <FaArrowLeft /> Back
        </button>
        
        <div style={styles.searchQuery}>
          <h1 style={styles.title}>
            <FaSearch /> Search Results
          </h1>
          <p style={styles.queryText}>"{query}"</p>
          <p style={styles.resultCount}>{results.length} results found</p>
        </div>
      </div>

      {/* Filters */}
      <div style={styles.filters}>
        <button 
          style={{
            ...styles.filterBtn,
            ...(activeFilter === 'all' ? styles.activeFilter : {})
          }}
          onClick={() => setActiveFilter('all')}
        >
          All
        </button>
        <button 
          style={{
            ...styles.filterBtn,
            ...(activeFilter === 'course' ? styles.activeFilter : {})
          }}
          onClick={() => setActiveFilter('course')}
        >
          <FaBook /> Courses
        </button>
        <button 
          style={{
            ...styles.filterBtn,
            ...(activeFilter === 'subject' ? styles.activeFilter : {})
          }}
          onClick={() => setActiveFilter('subject')}
        >
          📚 Subjects
        </button>
        <button 
          style={{
            ...styles.filterBtn,
            ...(activeFilter === 'notes' ? styles.activeFilter : {})
          }}
          onClick={() => setActiveFilter('notes')}
        >
          <FaFileAlt /> Notes
        </button>
        <button 
          style={{
            ...styles.filterBtn,
            ...(activeFilter === 'pyq' ? styles.activeFilter : {})
          }}
          onClick={() => setActiveFilter('pyq')}
        >
          <FaHistory /> PYQs
        </button>
      </div>

      {/* Results */}
      <div>
        {loading ? (
          <div style={styles.loading}>
            <div style={styles.spinner}></div>
            <p>Searching for "{query}"...</p>
          </div>
        ) : filteredResults.length > 0 ? (
          <div style={styles.resultsGrid}>
            {filteredResults.map((item) => {
              // Type colors
              const typeColors = {
                course: { bg: '#dbeafe', color: '#1d4ed8' },
                subject: { bg: '#dcfce7', color: '#166534' },
                notes: { bg: '#fef3c7', color: '#92400e' },
                pyq: { bg: '#e0e7ff', color: '#4f46e5' }
              };
              
              const typeStyle = typeColors[item.type] || { bg: '#f3f4f6', color: '#6b7280' };

              return (
                <div 
                  key={item.id} 
                  style={styles.resultCard}
                  onClick={() => navigate(item.path)}
                >
                  <div style={styles.resultIcon}>{item.icon}</div>
                  <div style={styles.resultContent}>
                    <h3 style={styles.resultTitle}>{item.title}</h3>
                    <p style={styles.resultDesc}>{item.description}</p>
                    <span style={{
                      ...styles.resultType,
                      background: typeStyle.bg,
                      color: typeStyle.color
                    }}>
                      {item.type.charAt(0).toUpperCase() + item.type.slice(1)}
                    </span>
                  </div>
                </div>
              );
            })}
          </div>
        ) : (
          <div style={styles.noResults}>
            <FaSearch style={{ fontSize: '4rem', color: '#d1d5db', marginBottom: '1rem' }} />
            <h3>No results found for "{query}"</h3>
            <p>Try searching with different keywords</p>
            <button 
              style={styles.searchAgainBtn}
              onClick={() => navigate('/')}
            >
              Search Again
            </button>
          </div>
        )}
      </div>

      {/* Add CSS animation */}
      <style>
        {`
          @keyframes spin {
            0% { transform: rotate(0deg); }
            100% { transform: rotate(360deg); }
          }
          
          @import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap');
          
          button:hover {
            transform: translateY(-2px);
          }
          
          .result-card:hover {
            transform: translateY(-5px) !important;
          }
        `}
      </style>
    </div>
  );
};

export default SearchResults;
